INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1001, 0, 0, "春咲 ひより", 0, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1, 1, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1, 2, "お！\nあそこに困ってそうな人発見！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1002, 0, 0, "草野 優衣", 0, 0, "みんなみたいに\nわたしも強くならなきゃ", 1, 1, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1, 2, "大切な人を\n守れるようになりたい…って");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1003, 0, 0, "士条 怜", 0, 0, "フェンシングを始めてみては？", 1, 1, "少しは磨かれると思いますよ。", 1, 2, "キミに必要な集中力と感性が");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1004, 0, 0, "穂高 みそぎ", 0, 0, "ねぇ、にいちゃん！", 1, 1, "みそぎはねぇ、\nかくれんぼやりたい！", 1, 2, "今日はなにして遊ぶ？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1006, 0, 0, "風宮 あかり", 0, 0, "風宮あかりです", 1, 1, "私といっしょに…\nいかない？", 1, 2, "ねぇ…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1007, 0, 0, "出雲 宮子", 0, 0, "出雲宮子なのー", 1, 1, "食べ物の恨みは怖いのー", 1, 2, "プリンたべたいのー");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1008, 0, 0, "虹村 雪", 0, 0, "ボクは虹村雪。", 1, 1, "いいよ。\n見られることは運命さ…", 1, 2, "キミもボクの美貌に\n吸い寄せられたんだね。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1009, 0, 0, "柊杏奈", 0, 0, "フッ…聞いて後悔するがいい！", 1, 1, "人呼んで「疾風の冥姫」!!", 1, 2, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1010, 0, 0, "姫宮 真歩", 0, 0, "マホマホ王国のプリンセス、\nまほ姫どす", 1, 1, "ほんまおおきにやわ～♪", 1, 2, "うさぎさん、\n運命の王子はんに巡りあわせてくれて");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1011, 0, 0, "衣之咲 璃乃", 0, 0, "衣之咲璃乃です！", 1, 1, "ここで会ったが\n100年目～！", 1, 2, "生き別れたお兄ちゃんを探して\n三千世界！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1012, 0, 0, "柏崎 初音", 0, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1, 1, "…って、お願い！\n誰にも言わないでおいて～！", 1, 2, "ち、超能力って…\n何のことかな～？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1016, 0, 0, "美波 鈴奈", 0, 0, "ちょす！\n美波鈴奈だよ～♪", 1, 1, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1, 2, "一応カリスマ読モJKやってまっす！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1017, 0, 0, "喜屋武 香織", 0, 0, "はいたーい。\n喜屋武香織さー。", 1, 1, "でも、沖縄もとってもいいとこさー", 1, 2, "東京は遊園地みたいなところさー");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1018, 0, 0, "支倉 伊緒", 0, 0, "支倉伊緒です。", 1, 1, "イオちゃんって呼んでね。", 1, 2, "先生って呼ばれるのは\nくすぐったいから");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1020, 0, 0, "茜 ミミ", 0, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1, 1, "ミミをおいてかないでぇ～", 1, 2, "あ！/\お兄ちゃ～ん\nまってよ～");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1021, 0, 0, "栗林 くるみ", 0, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", 1, 1, "ふぇぇぇぇぇん……", 1, 2, "あの……\nふぇ……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1022, 0, 0, "風宮 より", 0, 0, "風宮よりです。\nあああああ！", 1, 1, "なんてありがとうございます！", 1, 2, "こんな私に貴重な時間を\n割いていただき、");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1023, 0, 0, "北条 綾音", 0, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1, 1, "私こっち行きたいー\nね、早く早くー", 1, 2, "おにいちゃんどこいくの？\nえ？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1025, 0, 0, "天野 すずめ", 0, 0, "わっ…わっ…私、\n天野すずめといいます！", 1, 1, "これて何か違う…\nあああすみません！", 1, 2, "ふ、不束者ですが\nどうぞ末永く…って、");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1027, 0, 0, "倉石 恵理子", 0, 0, "……クスクス…私は\n…倉石恵理子……", 1, 1, "離しませんわ………\n絶対に…!!", 1, 2, "あなたは…運命の……\n伴侶……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1028, 0, 0, "佐々木 咲恋", 0, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1, 1, "…そうでしょ？？", 1, 2, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1029, 0, 0, "桜井 望", 0, 0, "桜井望だよ！\nよろしくねっ", 1, 1, "あはは、\n私もまだまだだなぁ～", 1, 2, "ぇっと…\nキミ、私のこと知らないの?!");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1030, 0, 0, "ニノン・ジュベール", 0, 0, "デケデケデンっ！", 1, 1, "ショーグン、\nワタシと一緒に天下統一デース！", 1, 2, "初めまして、\n私はニノン・ジュベール申すデス！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1031, 0, 0, "上喜 しのぶ", 0, 0, "上喜しのぶです。\n手元のドクロが父です。", 1, 1, "おかしいですね……", 1, 2, "でもって私の隣にいるのが……\nえ、見えない？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1033, 0, 0, "野戸まひる", 0, 0, "目指すはビッグな\nお笑い芸人だっぺ！", 1, 1, "そう、\nオラのボケに突っ込める相方が…！", 1, 2, "けんども\nそれには足りないモンが…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1034, 0, 0, "綾瀬 ゆかり", 0, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1, 1, "ちょ\nちょっと一杯飲んできます…！", 1, 2, "ちょっと緊張しちゃって…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1036, 0, 0, "氷川 鏡華", 0, 0, "氷川鏡華…です", 1, 1, "これ以上お話しすることは…\nないです！", 1, 2, "知らない人とは話しちゃいけないので");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1038, 0, 0, "柏崎 栞", 0, 0, "柏崎…栞です。", 1, 1, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1, 2, "……あ、アラーム。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1040, 0, 0, "双葉 碧", 0, 0, "ふ、双葉碧です。", 1, 1, "野に咲く花が、\n唯一の話相手です。", 1, 2, "私、一人も友達がいなくて……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1042, 0, 0, "三角 千歌", 0, 0, "三角千歌です。", 1, 1, "そう思っています。", 1, 2, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1043, 0, 0, "安芸 真琴", 0, 0, "安芸真琴だ。", 1, 1, "う、疑ってすまなかったな…", 1, 2, "あぁ？\nお前のそいつの仲間か？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1044, 0, 0, "イリヤ・オーンスタイン", 0, 0, "わらわこそは夜を総べる者！", 1, 1, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1, 2, "生けとし生ける全ての者よ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1045, 0, 0, "遠見 空花", 0, 0, "そこで騎士は妖精を乱暴に……", 1, 1, "ｌク、クウカに何かご用ですか!?", 1, 2, "ぐふふふふ……はっ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1046, 0, 0, "宮坂たまき", 0, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1, 1, "う～ん…\n猫ってホントに最高にゃ～♪", 1, 2, "自由気ままで♪\n寝て遊んで、食べてケンカして…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1048, 0, 0, "大神 美冬", 0, 0, "大神美冬よ！", 1, 1, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1, 2, "それでは早速クエストに…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1049, 0, 0, "星野静流", 0, 0, "星野静流だよ！", 1, 1, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1, 2, "クエストもバトルも\n掃除も洗濯も");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1050, 0, 0, "玉泉美咲", 0, 0, "アタシは玉泉美咲。", 1, 1, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1, 2, "見ての通りの\nセクシー美少女で");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.4, 1052, 0, 0, "リマ", 0, 0, "？？？", 1, 1, "？？？？", 1, 2, "？？？？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1053, 0, 0, "モニカ・ヴァイスヴィント", 0, 0, "モニカ・ヴァイスヴィントだ。", 1, 1, "そ、そこまでいうなら\nもらってやる", 1, 2, "菓子でつろうなどと\n稚拙な策を……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1058, 0, 0, "ペコリーヌ", 0, 0, "モニカ・ヴァイスヴィントだ。", 1, 1, "そ、そこまでいうなら\nもらってやる", 1, 2, "菓子でつろうなどと\n稚拙な策を……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1059, 0, 0, "コッコロ", 0, 0, "モニカ・ヴァイスヴィントだ。", 1, 1, "そ、そこまでいうなら\nもらってやる", 1, 2, "菓子でつろうなどと\n稚拙な策を……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, 1.5, 1060, 0, 0, "キャル", 0, 0, "モニカ・ヴァイスヴィントだ。", 1, 1, "そ、そこまでいうなら\nもらってやる", 1, 2, "菓子でつろうなどと\n稚拙な策を……");
